+interface CharState { x: number; y: number; tx: number; ty: number; dir: string; wf: number; moving: boolean; idle: number }
+const charStates = new Map<string, CharState>();
+
+function getCS(id: string, sx: number, sy: number): CharState {
+  if (!charStates.has(id)) charStates.set(id, { x: sx, y: sy, tx: sx, ty: sy, dir: 'down', wf: 0, moving: false, idle: Math.random() * 200 });
+  return charStates.get(id)!;
+}
+
+function updateMovement(cs: CharState, bounds: { x: number; y: number; w: number; h: number }) {
+  const dx = cs.tx - cs.x, dy = cs.ty - cs.y;
+  const dist = Math.sqrt(dx * dx + dy * dy);
+  if (dist > 2) {
+    cs.moving = true;
+    cs.x += (dx / dist) * 0.4;
+    cs.y += (dy / dist) * 0.4;
+    cs.wf = (cs.wf + 1) % 40; // cycle walk frame counter smoothly
+    cs.dir = Math.abs(dx) > Math.abs(dy) ? (dx > 0 ? 'right' : 'left') : (dy > 0 ? 'down' : 'up');
+  } else {
+    cs.moving = false; cs.wf = 0; cs.idle--;
+    if (cs.idle <= 0) {
+      const mx = bounds.w * 0.15, my = bounds.h * 0.2;
+      cs.tx = bounds.x + mx + Math.random() * (bounds.w - mx * 2);
+      cs.ty = bounds.y + my + Math.random() * (bounds.h - my * 2);
+      cs.idle = 150 + Math.random() * 300;
+    }
+  }
+}
+
+// Draw character with walk cycle animation
+function drawCharacter(ctx: CanvasRenderingContext2D, id: string, x: number, y: number, tier: string, state: AnimState, job: string | null) {
+  const cs = getCS(id, x, y);
+  const baseX = Math.round(cs.x);
+  const baseY = Math.round(cs.y);
+
+  // Determine walk frame index (0-3) for 4-frame cycle
+  const walkFrame = cs.moving ? Math.floor(cs.wf / 10) % 4 : 0;
+
+  // Draw body (simple rectangle for demo)
+  ctx.fillStyle = '#654321';
+  ctx.fillRect(baseX - 8, baseY - 16, 16, 16);
+
+  // Draw head
+  ctx.fillStyle = '#f1c27d';
+  ctx.beginPath();
+  ctx.arc(baseX, baseY - 20, 6, 0, Math.PI * 2);
+  ctx.fill();
+
+  // Draw legs with walk animation
+  ctx.strokeStyle = '#000000';
+  ctx.lineWidth = 2;
+  ctx.lineCap = 'round';
+  ctx.beginPath();
+
+  // Leg offset pattern for 4 frames: legs move opposite
+  // frame 0: left leg forward, right leg back
+  // frame 1: legs neutral
+  // frame 2: right leg forward, left leg back
+  // frame 3: legs neutral
+  const legOffsets = [
+    { left: -2, right: 2 },
+    { left: 0, right: 0 },
+    { left: 2, right: -2 },
+    { left: 0, right: 0 },
+  ];
+  const offsets = legOffsets[walkFrame];
+
+  // Left leg
+  ctx.moveTo(baseX - 4, baseY);
+  ctx.lineTo(baseX - 4 + offsets.left, baseY + 12);
+
+  // Right leg
+  ctx.moveTo(baseX + 4, baseY);
+  ctx.lineTo(baseX + 4 + offsets.right, baseY + 12);
+
+  ctx.stroke();
+
+  // Draw arms (static for now)
+  ctx.beginPath();
+  ctx.moveTo(baseX - 8, baseY - 8);
+  ctx.lineTo(baseX - 12, baseY + 4);
+  ctx.moveTo(baseX + 8, baseY - 8);
+  ctx.lineTo(baseX + 12, baseY + 4);
+  ctx.stroke();
+
+  // Draw speech bubble if any
+  drawBubble(ctx, id, baseX, baseY - 28);
+}
+export { getCS, updateMovement, drawCharacter };
